import React, { Component } from 'react';
import './SNSLink.css';
import { replace_no_img } from './utils';
//import exportFunction from "./utils"

class SNSLink extends Component {

    render() {
        const {
            type,
            id,
            link,
            logo_src
        } = this.props;

        if (type == "github") {
            const {
                link = "https://github.com/" + id,
                src = "./github.png"
            } = this.props;
        }
        else{
        }

        const openWindow = () => {
            window.open(link, '_blank');
        }

        return (
            <button className="SNSBtn" onClick={openWindow}>
                <img className="logo" src={replace_no_img(logo_src)}></img>
            </button>
        );
    }
}

export default SNSLink;
